// Compliant: Switch statements with proper default clauses
func processUserRole(role string) string {
    switch role {
    case "admin":
        return "Administrator access granted"
    case "editor":
        return "Editor access granted"
    case "viewer":
        return "Viewer access granted"
    default:
        return "Unknown role - access denied"
    }
}

// Compliant: Type switch with proper default handling
func handleValue(value interface{}) {
    switch v := value.(type) {
    case string:
        fmt.Printf("String: %s\n", v)
    case int:
        fmt.Printf("Integer: %d\n", v)
    case bool:
        fmt.Printf("Boolean: %t\n", v)
    default:
        fmt.Printf("Unsupported type: %T\n", v)
    }
}

// Compliant: Status code with fallback message
func getStatusMessage(code int) string {
    switch code {
    case 200:
        return "OK"
    case 404:
        return "Not Found"
    case 500:
        return "Internal Server Error"
    default:
        return fmt.Sprintf("Unknown status code: %d", code)
    }
}

// Compliant: Enum handling with sensible default
func getLogLevel(level string) int {
    switch strings.ToUpper(level) {
    case "DEBUG":
        return 0
    case "INFO":
        return 1
    case "WARN":
        return 2
    case "ERROR":
        return 3
    default:
        return 1 // Default to INFO level for unknown values
    }
}

